export { render, renderHudLine } from "./grid.js";
export {
  ALL_LOG_EVENT_TYPES,
  dummyLogEvent,
  formatLogEvent,
} from "./log.js";

import { idx, type Tile } from "../map/index.js";
import type {
  EntityId,
  EntityInstance,
  GameState,
  Position,
} from "../state/index.js";
import {
  defaultVisibleFog,
  fogFromState,
  floorKnowledge,
  gridFromState,
  isTrapRevealed,
} from "./floor-runtime.js";
import {
  enemyGlyph,
  GLYPH_NPC,
  GLYPH_PLAYER,
  GLYPH_TRAP,
  itemGlyph,
  rememberedTerrainGlyph,
  terrainGlyph,
} from "./glyphs.js";

export const renderHudLine = (state: GameState): string => {
  const statuses = state.player.statuses
    .map((application) => application.status)
    .join(",");
  const statusSuffix = statuses.length > 0 ? ` ${statuses}` : "";

  return [
    `d${state.run.depth}`,
    `t${state.run.turn}`,
    `HP ${state.player.hp.current}/${state.player.hp.max}`,
    `full ${state.player.fullness.current}/${state.player.fullness.max}`,
    `L${state.player.level}`,
    `xp ${state.player.xp}${statusSuffix}`,
  ].join(" ");
};

export const render = (state: GameState): string => {
  const grid = gridFromState(state);

  if (grid === null) {
    return renderHudLine(state);
  }

  const fog = fogFromState(state, grid) ?? defaultVisibleFog(grid);
  const knowledge = floorKnowledge(state);
  const mapRevealed = knowledge.mapRevealed === true;
  const lines: string[] = [];

  for (let y = 0; y < grid.height; y += 1) {
    let row = "";

    for (let x = 0; x < grid.width; x += 1) {
      const position = { x, y };
      const index = idx(grid, position);
      const memory = fog.tiles[index];

      if (memory === undefined) {
        row += " ";
        continue;
      }

      if (!mapRevealed && memory.state === "unseen") {
        row += " ";
        continue;
      }

      if (!mapRevealed && memory.state === "remembered") {
        const tile = memory.rememberedTile;

        row += tile === null ? " " : rememberedTerrainGlyph(tile);
        continue;
      }

      const tile = grid.tiles[index];

      row +=
        tile === undefined ? " " : glyphAt(state, position, tile);
    }

    lines.push(row);
  }

  lines.push(renderHudLine(state));

  return lines.join("\n");
};

const glyphAt = (state: GameState, position: Position, tile: Tile): string => {
  if (
    state.player.position.x === position.x &&
    state.player.position.y === position.y
  ) {
    return GLYPH_PLAYER;
  }

  const entities = entitiesAt(state, position);

  const enemy = entities.find((entity) => entity.kind === "enemy");

  if (enemy !== undefined) {
    return enemyGlyph(enemy.definition.glyph);
  }

  const npc = entities.find((entity) => entity.kind === "npc");

  if (npc !== undefined) {
    return GLYPH_NPC;
  }

  const item = entities.find((entity) => entity.kind === "item");

  if (item !== undefined) {
    return itemGlyph(item.definition, item.identified);
  }

  const trap = entities.find((entity) => entity.kind === "trap");

  if (
    trap !== undefined &&
    isTrapRevealed(state, trap.id, trap.behaviorRuntime)
  ) {
    return GLYPH_TRAP;
  }

  return terrainGlyph(tile);
};

const entitiesAt = (
  state: GameState,
  position: Position,
): readonly EntityInstance[] =>
  Object.values(state.entities)
    .filter(
      (entity) =>
        entity.position.x === position.x && entity.position.y === position.y,
    )
    .sort((left, right) => compareEntityIds(left.id, right.id));

const compareEntityIds = (left: EntityId, right: EntityId): number => {
  const parsedLeft = parseEntityId(left);
  const parsedRight = parseEntityId(right);
  const kindOrder = parsedLeft.kind.localeCompare(parsedRight.kind);

  return kindOrder === 0
    ? parsedLeft.index - parsedRight.index
    : kindOrder;
};

const parseEntityId = (
  id: EntityId,
): { readonly kind: string; readonly index: number } => {
  const [kind, rawIndex] = id.split("#");

  return {
    kind: kind ?? "",
    index: Number.parseInt(rawIndex ?? "0", 10),
  };
};

// PHASE-49A must mirror the ASCII grid renderer only. The public render barrel
// also re-exports log formatting, which currently pulls unrelated event-union
// type errors into app typecheck.
// eslint-disable-next-line no-restricted-imports
import { render } from "@engine/render/grid";
import type {
  EntityId,
  EntityInstance,
  GameState,
  Position,
} from "@engine/state";

export type GridFogState = "visible" | "remembered" | "unseen";

export type GridLayer =
  | "player"
  | "enemy"
  | "npc"
  | "item"
  | "trap"
  | "terrain"
  | "empty";

export type GridShape =
  | "none"
  | "circle"
  | "diamond"
  | "square"
  | "dot"
  | "triangle";

export type GridPulseKind = "damage" | "heal";

export type GridPulse = {
  readonly id: string;
  readonly kind: GridPulseKind;
  readonly text: string;
};

export type GridMotion = {
  readonly dx: number;
  readonly dy: number;
};

export type GridCellView = {
  readonly key: string;
  readonly x: number;
  readonly y: number;
  readonly glyph: string;
  readonly fog: GridFogState;
  readonly layer: GridLayer;
  readonly label: string;
  readonly badge: string;
  readonly shape: GridShape;
  readonly pulses: readonly GridPulse[];
  readonly hitFlash: boolean;
  readonly motion: GridMotion | null;
  readonly renderKey: string;
};

export type GridRenderCursor = {
  readonly runId: string;
  readonly floorId: string;
  readonly logLength: number;
};

export type GridViewModel = {
  readonly width: number;
  readonly height: number;
  readonly cells: readonly GridCellView[];
  readonly rows: readonly (readonly GridCellView[])[];
  readonly cursor: GridRenderCursor;
};

type CellEffects = {
  readonly pulses: readonly GridPulse[];
  readonly hitFlash: boolean;
  readonly motion: GridMotion | null;
};

type MutableCellEffects = {
  pulses: GridPulse[];
  hitFlash: boolean;
  motion: GridMotion | null;
};

type RuntimeLogEvent = {
  readonly turn?: unknown;
  readonly type?: unknown;
  readonly data?: unknown;
};

type RuntimeFogTile = {
  readonly state?: unknown;
};

type RuntimeRecord = {
  readonly [key: string]: unknown;
};

const EMPTY_EFFECTS: CellEffects = {
  pulses: [],
  hitFlash: false,
  motion: null,
};

const ENTITY_KIND_ORDER: Readonly<Record<EntityInstance["kind"], number>> = {
  enemy: 0,
  item: 1,
  npc: 2,
  trap: 3,
};

export const hasRenderableGrid = (state: GameState): boolean =>
  renderedGridLines(state).length > 0;

export const createGridViewModel = (
  state: GameState,
  previousCursor?: GridRenderCursor,
): GridViewModel => {
  const lines = renderedGridLines(state);
  const width = lines[0]?.length ?? 0;
  const height = lines.length;
  const cursor = cursorForState(state);
  const entitiesByPosition = entitiesByCell(state);
  const fogStates = fogStatesForState(state, width, height);
  const effectsByPosition = effectsSinceLastRender(state, previousCursor);
  const cells: GridCellView[] = [];

  for (let y = 0; y < height; y += 1) {
    const line = lines[y] ?? "";

    for (let x = 0; x < width; x += 1) {
      const glyph = line.charAt(x) || " ";
      const positionKey = keyForPosition({ x, y });
      const fog = fogStates[y * width + x] ?? "unseen";
      const layer = layerAt(
        state,
        { x, y },
        glyph,
        fog,
        entitiesByPosition.get(positionKey) ?? [],
      );
      const effects = effectsByPosition.get(positionKey) ?? EMPTY_EFFECTS;
      cells.push(
        createCell({
          x,
          y,
          glyph,
          fog,
          layer,
          effects,
        }),
      );
    }
  }

  return {
    width,
    height,
    cells,
    rows: rowsForCells(cells, width),
    cursor,
  };
};

const renderedGridLines = (state: GameState): readonly string[] => {
  const lines = render(state).split("\n");

  return lines.length > 1 ? lines.slice(0, -1) : [];
};

const cursorForState = (state: GameState): GridRenderCursor => ({
  runId: state.run.runId,
  floorId: state.floor.floorId,
  logLength: state.log.length,
});

const rowsForCells = (
  cells: readonly GridCellView[],
  width: number,
): readonly (readonly GridCellView[])[] => {
  if (width <= 0) {
    return [];
  }

  const rows: GridCellView[][] = [];

  for (let offset = 0; offset < cells.length; offset += width) {
    rows.push(cells.slice(offset, offset + width));
  }

  return rows;
};

const createCell = ({
  x,
  y,
  glyph,
  fog,
  layer,
  effects,
}: {
  readonly x: number;
  readonly y: number;
  readonly glyph: string;
  readonly fog: GridFogState;
  readonly layer: GridLayer;
  readonly effects: CellEffects;
}): GridCellView => {
  const affordance = affordanceForLayer(layer);

  return {
    key: `${x}:${y}`,
    x,
    y,
    glyph,
    fog,
    layer,
    label: labelForLayer(layer, fog),
    badge: affordance.badge,
    shape: affordance.shape,
    pulses: effects.pulses,
    hitFlash: effects.hitFlash,
    motion: effects.motion,
    renderKey: [
      glyph,
      fog,
      layer,
      affordance.badge,
      affordance.shape,
      effects.hitFlash ? "hit" : "",
      effects.motion === null
        ? ""
        : `${effects.motion.dx},${effects.motion.dy}`,
      ...effects.pulses.map((pulse) => `${pulse.id}:${pulse.kind}:${pulse.text}`),
    ].join("|"),
  };
};

const affordanceForLayer = (
  layer: GridLayer,
): { readonly badge: string; readonly shape: GridShape } => {
  switch (layer) {
    case "player":
      return { badge: "YOU", shape: "circle" };
    case "enemy":
      return { badge: "FOE", shape: "diamond" };
    case "npc":
      return { badge: "NPC", shape: "square" };
    case "item":
      return { badge: "ITM", shape: "dot" };
    case "trap":
      return { badge: "TRP", shape: "triangle" };
    case "terrain":
    case "empty":
      return { badge: "", shape: "none" };
  }
};

